from jinja2 import Template

DEFAULT_SUBJECT = "Участие в фестивале “Мужской движ” 29–31 мая в Сибэкспоцентре"
DEFAULT_BODY = """Здравствуйте{% if contact_name %}, {{ contact_name }}{% endif %}!\n\nМеня зовут Марк, я занимаюсь привлечением участников на фестиваль “Мужской движ” в Сибэкспоцентре.\n\nМы собираем площадку для компаний, которые продают товары и услуги для мужской аудитории: авто, мото, тюнинг, инструменты, техника, охота, рыбалка, туризм, активный отдых, гаджеты, спорт и смежные направления.\n\nФормат события — не классическая выставка с табличками, а площадка опыта: гости тестируют, участвуют, соревнуются, общаются и знакомятся с продуктами вживую.\n\nПодумал, что компании “{{ company }}” может быть интересно участие или партнерская интеграция.\n{% if ai_comment %}{{ ai_comment }}\n{% endif %}\nВо вложении отправляю коммерческое предложение.\nБуду рад коротко обсудить, какой формат участия может подойти именно вам.\n\nС уважением,\nМарк\nСибэкспоцентр\n[телефон]\n[сайт/ссылка]\n\nЕсли письмо неактуально, ответьте “не интересно” — больше не будем беспокоить."""


def render_text(template_text: str, context: dict) -> str:
    return Template(template_text).render(**context)


def generate_email(context: dict, subject_template: str = DEFAULT_SUBJECT, body_template: str = DEFAULT_BODY) -> tuple[str, str]:
    return render_text(subject_template, context), render_text(body_template, context)
